window.QUESTION_BANK = [{"id":1,"question":"How are target resolution times used in the 'incident management' practice?","options":{"A":"They are agreed, documented, and communicated to help set user expectations","B":"They are established, reviewed, and reported to ensure that customers are happy with the service","C":"They are initiated, approved, and managed to ensure that predictable responses are achieved","D":"They are scheduled, assessed and authorized to reduce the risk of service failures"},"answer":"A","category":"Incident Management"},{"id":2,"question":"Why should some service requests be fulfilled with no additional approvals?","options":{"A":"To ensure that spending is properly accounted for","B":"To ensure that information security requirements are met","C":"To streamline the fulfilment workflow","D":"To set user expectations for fulfilment times"},"answer":"C","category":"Service Request Management"},{"id":3,"question":"What is a set of specialized organizational capabilities for enabling value for customers in the form of services?","options":{"A":"Service offering","B":"Service provision","C":"Service management","D":"Service consumption"},"answer":"C","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":4,"question":"Which gives a user access to a system?","options":{"A":"Service requirement","B":"Service agreement","C":"Service consumption","D":"Service provision"},"answer":"D","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":5,"question":"Which statement about managing incidents is CORRECT?","options":{"A":"Low impact incidents should be resolved efficiently, making logging unnecessary","B":"The 'incident management' practice should use a single process regardless of the impact of the incident","C":"Low impact incidents should be resolved efficiently so the resource required is reduced","D":"Incidents with the lowest impact should be resolved first"},"answer":"C","category":"Incident Management"},{"id":6,"question":"Which statement about the service value chain is CORRECT?","options":{"A":"The service value chain converts value into demand","B":"Each value chain activity uses different combinations of practices to convert inputs into outputs","C":"Each value chain activity identifies a requirement for resources from an external supplier","D":"The service value chain uses value streams to describe a combination of consumers and providers"},"answer":"B","category":"Service Value Chain"},{"id":7,"question":"What describes how components and activities work together to facilitate value creation?","options":{"A":"The ITIL service value system","B":"The ITIL guiding principles","C":"The four dimensions of service management","D":"A service relationship"},"answer":"A","category":"Guiding Principles"},{"id":8,"question":"Which practice involves the management of vulnerabilities that were not identified before the service went live?","options":{"A":"Service request management","B":"Problem management","C":"Change control","D":"Service level management"},"answer":"B","category":"Change Enablement"},{"id":9,"question":"Which statement about the use of measurement in the 'start where you are' guiding principle is CORRECT?","options":{"A":"It should always be used to support direct observation","B":"It should always be used instead of direct observation","C":"Measured data is always more accurate than direct observation","D":"The act of measuring always positively impacts results"},"answer":"A","category":"Guiding Principles"},{"id":10,"question":"Which ITIL practice recommends performing service reviews to ensure that services continue to meet the needs of the organization?","options":{"A":"Service desk","B":"Service request management","C":"Service level management","D":"Service configuration management"},"answer":"C","category":"Service Desk"},{"id":11,"question":"What should be considered as part of the 'partners and suppliers' dimension?","options":{"A":"The level of integration and formality involved in the relationships between organizations","B":"The activities, workflows, controls and procedures needed to achieve the agreed objectives","C":"The information created, managed and used in the course of service provision and consumption","D":"The required skills and competencies of teams and individual members of the organization"},"answer":"A","category":"Four Dimensions of Service Management"},{"id":12,"question":"Which practice makes new services available for use?","options":{"A":"Change enablement","B":"Release management","C":"Deployment management","D":"IT asset management"},"answer":"B","category":"Change Enablement"},{"id":13,"question":"Which activity contributes to the 'where are we now?' step of the 'continual improvement' model?","options":{"A":"Executing improvement actions","B":"Performing baseline assessments","C":"Defining the improvement plan","D":"Understanding the business mission"},"answer":"B","category":"Continual Improvement"},{"id":14,"question":"Which guiding principle considers the importance of customer loyalty?","options":{"A":"Progress iteratively with feedback","B":"Focus on value","C":"Optimize and automate","D":"Start where you are"},"answer":"B","category":"Guiding Principles"},{"id":15,"question":"Which is a recommendation of the guiding principle 'think and work holistically'?","options":{"A":"Conduct a review of existing service management practices and decide what to keep and what to discard","B":"Review how an improvement initiative can be organized into smaller, manageable sections that can be completed in a timely manner","C":"Review service management practices and remove any unnecessary complexity","D":"Use the four dimensions of service management to ensure coordination of all aspects of an improvement initiative"},"answer":"D","category":"Guiding Principles"},{"id":16,"question":"Which statement about 'continual improvement' is CORRECT?","options":{"A":"All improvement ideas should be logged in a single 'continual improvement register'","B":"A single team should carry out 'continual improvement' across the organization","C":"'Continual improvement' should have minimal interaction with other practices","D":"Everyone in the organization is responsible for some aspects of 'continual improvement'"},"answer":"D","category":"Continual Improvement"},{"id":17,"question":"What impact does automation have on a service desk?","options":{"A":"Less low level work and a greater ability to focus on user experience","B":"Increased phone contact and a reduced ability to focus on user experience","C":"Ability to work from multiple locations, geographically dispersed","D":"Ability to work from a single centralized location"},"answer":"A","category":"Service Desk"},{"id":18,"question":"Identify the missing word(s) in the following sentence: The service desk should be the entry point and single point of contact for the [?] with all of its users.","options":{"A":"Service consumer","B":"Service provider","C":"Customer","D":"Supplier"},"answer":"B","category":"Service Desk"},{"id":19,"question":"What aspect of 'service level management' asks service consumers what their work involves and how technology helps them?","options":{"A":"Customer engagement","B":"Operational metrics","C":"Business metrics","D":"Customer feedback"},"answer":"A","category":"Service Level Management"},{"id":20,"question":"Which is a result of applying the guiding principle 'progress iteratively with feedback'?","options":{"A":"The ability to discover and respond to failure earlier","B":"Standardization of practices and services","C":"Understanding the customer's perception of value","D":"Understanding the current state and identifying what can be reused"},"answer":"A","category":"Guiding Principles"},{"id":21,"question":"What can be used to determine if a service is 'fit for purpose'?","options":{"A":"Availability","B":"Warranty","C":"Outcome","D":"Utility"},"answer":"D","category":"General Concepts"},{"id":22,"question":"In service relationships, what is a benefit of identifying consumer roles?","options":{"A":"It enables effective stakeholder management","B":"It provides shared service expectations","C":"It removes constraints from the customer","D":"It enables a common definition of value"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":23,"question":"Which is an external input to the service value chain?","options":{"A":"The 'improve' value chain activity","B":"An overall plan","C":"Customer requirements","D":"Feedback loops"},"answer":"C","category":"Service Value Chain"},{"id":24,"question":"What term is used to describe whether a service will meet availability, capacity and security requirements?","options":{"A":"Outcomes","B":"Value","C":"Utility","D":"Warranty"},"answer":"D","category":"General Concepts"},{"id":25,"question":"What is the purpose of the 'incident management' practice?","options":{"A":"To minimize the negative impact of incidents by restoring normal service operation as quickly as possible","B":"To capture demand for incident resolution and service requests","C":"To reduce the likelihood and impact of incidents by identifying actual and potential causes of incidents","D":"To support the agreed service quality by effective handling of all agreed user-initiated service requests"},"answer":"A","category":"Incident Management"},{"id":26,"question":"What is defined as an unplanned interruption or reduction in the quality of a service?","options":{"A":"An incident","B":"A problem","C":"A change","D":"An event"},"answer":"A","category":"General Concepts"},{"id":27,"question":"Which ITIL practice has the purpose to establish and nurture the links between the organization and its stakeholders at strategic and tactical levels?","options":{"A":"Supplier management","B":"Change control","C":"Relationship management","D":"Service desk"},"answer":"C","category":"Change Enablement"},{"id":28,"question":"What can help to reduce resistance to a planned improvement when applying the guiding principle 'collaborate and promote visibility'?","options":{"A":"Restricting information about the improvement to essential stakeholders only","B":"Increasing collaboration and visibility for the improvement","C":"Involving customers after all planning has been completed","D":"Engaging every stakeholder group in the same way, with the same communication"},"answer":"C","category":"Guiding Principles"},{"id":29,"question":"What varies in size and complexity, and uses functions to achieve its objectives?","options":{"A":"A risk","B":"An organization","C":"A practice","D":"An outcome"},"answer":"B","category":"General Concepts"},{"id":30,"question":"Which practice ensures that any addition, modification, or removal of anything that could have an effect on services is assessed and authorized?","options":{"A":"Deployment management","B":"Release management","C":"Change control","D":"Service configuration management"},"answer":"C","category":"Change Enablement"},{"id":31,"question":"Which practice has a purpose that includes managing risks to confidentiality, integrity and availability?","options":{"A":"Information security management","B":"Continual improvement","C":"Monitoring and event management","D":"Service level management"},"answer":"A","category":"Continual Improvement"},{"id":32,"question":"Which will help solve incidents more quickly?","options":{"A":"Target resolution times","B":"Escalating all incidents to support teams","C":"Collaboration between teams","D":"Detailed procedural steps for incident investigation"},"answer":"D","category":"General Concepts"},{"id":33,"question":"When is the earliest that a workaround can be documented in 'problem management'?","options":{"A":"After the problem has been logged","B":"After the problem has been prioritized","C":"After the problem has been analyzed","D":"After the problem has been resolved"},"answer":"C","category":"Problem Management"},{"id":34,"question":"Which is an activity of the 'problem management' practice?","options":{"A":"Restoration of normal service operation as quickly as possible","B":"Prioritization of problems based on the risk that they pose","C":"Authorization of changes to resolve the cause of problems","D":"Resolution of incidents in a time that meets customer expectations"},"answer":"B","category":"Problem Management"},{"id":35,"question":"Which practice is MOST likely to benefit from the use of chatbots?","options":{"A":"Service level management","B":"Change enablement","C":"Continual improvement","D":"Service desk"},"answer":"D","category":"Continual Improvement"},{"id":36,"question":"Where are the details of the required performance outcomes of a service defined?","options":{"A":"Service level agreements","B":"Service requests","C":"Service components","D":"Service offerings"},"answer":"A","category":"Service Level Management"},{"id":37,"question":"Which value chain activity ensures a shared understanding of the current status and required direction for all products and services?","options":{"A":"Plan","B":"Improve","C":"Design and transition","D":"Deliver and support"},"answer":"A","category":"Service Value Chain"},{"id":38,"question":"Which practice has the purpose of ensuring that the organization's suppliers and their performance are managed appropriately to support the provision of seamless, quality products and services?","options":{"A":"Release management","B":"Supplier management","C":"Service management","D":"Relationship management"},"answer":"B","category":"Release Management"},{"id":39,"question":"Which two practices interact the MOST with the service desk practice?","options":{"A":"Incident management and service request management","B":"Service request management and deployment management","C":"Deployment management and change enablement","D":"Change enablement and incident management"},"answer":"A","category":"Change Enablement"},{"id":40,"question":"Which is an activity of the 'incident management' practice?","options":{"A":"Assessing and prioritizing improvement opportunities","B":"Performing service reviews with customers","C":"Providing good-quality updates when expected","D":"Automating service requests to the greatest degree possible"},"answer":"C","category":"Incident Management"},{"id":41,"question":"Identify the missing words in the following sentence: A user is [?] that uses services.","options":{"A":"an organization","B":"a role","C":"a team","D":"a supplier"},"answer":"B","category":"Supplier Management"},{"id":42,"question":"Which is included in the purpose of the 'change enablement' practice?","options":{"A":"Make new and changed services available for use","B":"Ensure that risks have been properly assessed","C":"Record and report selected changes of state","D":"Plan and manage the full lifecycle of all IT assets"},"answer":"B","category":"Change Enablement"},{"id":43,"question":"Which activity is part of the 'continual improvement' practice?","options":{"A":"Identifying the cause of incidents and recommending related improvements","B":"Authorizing changes to implement improvements","C":"Logging and managing incidents that result in improvement opportunities","D":"Making business cases for improvement action"},"answer":"D","category":"Continual Improvement"},{"id":44,"question":"In which step of the 'continual improvement model' is an improvement plan implemented?","options":{"A":"What is the vision?","B":"How do we get there?","C":"Take action","D":"Did we get there?"},"answer":"C","category":"Continual Improvement"},{"id":45,"question":"Which is the BEST example of a standard change?","options":{"A":"The review and authorization of a change requested by a customer","B":"The implementation of a critical software patch in response to a vendor security issue","C":"The installation of a software application in response to a service request","D":"The replacement of a component in response to a major incident"},"answer":"C","category":"Change Enablement"},{"id":46,"question":"Which statement about the automation of service requests is CORRECT?","options":{"A":"Service requests that cannot be automated should be handled as incidents","B":"Service requests and their fulfilment should be automated as much as possible","C":"Service requests that cannot be automated should be handled as problems","D":"Service requests and their fulfilment should be carried out by service desk staff without automation"},"answer":"B","category":"Service Desk"},{"id":47,"question":"Which can act as an operating model for an organization?","options":{"A":"The four dimensions of service management","B":"The service value chain","C":"The ITIL guiding principles","D":"Continual improvement"},"answer":"B","category":"Guiding Principles"},{"id":48,"question":"Which practice recommends the use of event-based surveys to gather feedback from customers?","options":{"A":"Service level management","B":"Change enablement","C":"Service request management","D":"Problem management"},"answer":"A","category":"Change Enablement"},{"id":49,"question":"Which statement about change authorities is CORRECT?","options":{"A":"Change authorities are only required for authorizing emergency changes","B":"Change authorities are assigned when each change is deployed","C":"Change authorities are only required for authorizing normal changes","D":"Change authorities are assigned for each type of change and change model"},"answer":"D","category":"Change Enablement"},{"id":50,"question":"Which practice improves customer and user satisfaction by reducing the negative impact of service interruptions?","options":{"A":"Service request management","B":"Service level management","C":"Incident management","D":"Change enablement"},"answer":"C","category":"Change Enablement"},{"id":51,"question":"Which will NOT be handled as a service request?","options":{"A":"The degradation of a service","B":"The replacement of a toner cartridge","C":"The provision of a laptop","D":"A complaint about a support team"},"answer":"A","category":"Service Request Management"},{"id":52,"question":"A service offering may include goods, access to resources, and service actions. Which is an example of a service action?","options":{"A":"A mobile phone enables a user to work remotely","B":"A password allows a user connect to a WiFi network","C":"A license allows a user to install a software product","D":"A service desk agent provides support to a user"},"answer":"D","category":"Service Desk"},{"id":53,"question":"Which describes a CORRECT approach to change authorization?","options":{"A":"Changes included in the change schedule are pre-authorized and do not need additional authorization","B":"Normal changes should be assessed and authorized before they are deployed","C":"Emergency changes should be authorized by as many people as possible to reduce risk","D":"Normal changes are typically implemented as service requests and authorized by the service desk"},"answer":"B","category":"Change Enablement"},{"id":54,"question":"Which statement about a service value stream is CORRECT?","options":{"A":"It uses prescriptive inputs and outputs","B":"It is a value chain activity","C":"It integrates practices for a specific scenario","D":"It is used to provide governance"},"answer":"C","category":"Service Value Chain"},{"id":55,"question":"Which statement about outputs is CORRECT?","options":{"A":"They consist of several outcomes","B":"They capture customer demand for services","C":"They contribute to the achievement of outcomes","D":"They describe how the service performs"},"answer":"C","category":"General Concepts"},{"id":56,"question":"Which is an example of a business related measurement?","options":{"A":"The number of passengers checked in","B":"The average time to respond to change requests","C":"The average resolution time for incidents","D":"The number of problems resolved"},"answer":"A","category":"General Concepts"},{"id":57,"question":"Which BEST describes the purpose of the 'improve' value chain activity?","options":{"A":"To organize a major improvement initiative into several smaller initiatives","B":"To make new and improved services and features available for use","C":"To ensure a shared understanding of the vision and improvement direction for all products and services","D":"To continually improve all products and services across all value chain activities"},"answer":"D","category":"Service Value Chain"},{"id":58,"question":"Which includes governance, management practices, and continual improvement?","options":{"A":"The service value system","B":"The 'deliver and support' value chain activity","C":"The 'focus on value' guiding principle","D":"The 'value stream and processes' dimension"},"answer":"A","category":"Guiding Principles"},{"id":59,"question":"What is the definition of a problem?","options":{"A":"An unplanned interruption to a service, or reduction in the quality of a service","B":"A cause, or potential cause, of one or more incidents","C":"An incident for which a full resolution is not yet available","D":"Any change of state that has significance for the management of a configuration item (CI)"},"answer":"B","category":"Service Configuration Management"},{"id":60,"question":"Which practice provides a communications point for users to report operational issues, queries and requests?","options":{"A":"Incident management","B":"Continual improvement","C":"Service desk","D":"Relationship management"},"answer":"C","category":"Continual Improvement"},{"id":61,"question":"Which dimension is MOST concerned with skills, competencies, roles and responsibilities?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"A","category":"Four Dimensions of Service Management"},{"id":62,"question":"An organization asks a stakeholder to review a planned change. Which guiding principle does this demonstrate?","options":{"A":"Collaborate and promote visibility","B":"Start where you are","C":"Focus on value","D":"Keep it simple and practical"},"answer":"A","category":"Guiding Principles"},{"id":63,"question":"Which practice has a strong influence on the user experience and perception of the service provider?","options":{"A":"Service desk","B":"Change enablement","C":"Service level management","D":"Supplier management"},"answer":"A","category":"Change Enablement"},{"id":64,"question":"Which statement about service requests is CORRECT?","options":{"A":"Complex service requests should be dealt with as normal changes","B":"Service requests that require simple workflows should be dealt with as incidents","C":"Service requests require workflows that should use manual procedures and avoid automation","D":"Service requests are usually formalized using standard procedures for initiation, approval and fulfilment"},"answer":"D","category":"Change Enablement"},{"id":65,"question":"Which practice is responsible for moving new or changed components to live or other environments?","options":{"A":"Release management","B":"Deployment management","C":"Change enablement","D":"Supplier management"},"answer":"B","category":"Change Enablement"},{"id":66,"question":"Which dimension focuses on relationships with other organizations that are involved in the design, development, deployment and delivery of services?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"C","category":"Four Dimensions of Service Management"},{"id":67,"question":"Which of these activities is carried out as part of 'problem management'?","options":{"A":"Creating incident records","B":"Diagnosing and resolving incidents","C":"Escalating incidents to a support team for resolution","D":"Trend analysis of incident records"},"answer":"D","category":"Problem Management"},{"id":68,"question":"What must always be done before an activity is automated?","options":{"A":"Check that the activity has already been optimized","B":"Check that suitable new technology has been purchased","C":"Ensure that DevOps has been successfully implemented","D":"Ensure the solution removes the need for human intervention"},"answer":"A","category":"General Concepts"},{"id":69,"question":"What is a change schedule PRIMARILY used for?","options":{"A":"To help plan emergency changes","B":"To help authorize standard changes","C":"To help assign a change authority","D":"To help manage normal changes"},"answer":"D","category":"Change Enablement"},{"id":70,"question":"Which role approves the cost of services?","options":{"A":"User","B":"Change authority","C":"Sponsor","D":"Customer"},"answer":"C","category":"Change Enablement"},{"id":71,"question":"What actions does a service desk take for all issues, queries and requests that are reported to them?","options":{"A":"Schedule, assess, authorize","B":"Diagnose, investigate, resolve","C":"Initiate, approve, fulfil","D":"Acknowledge, classify, own"},"answer":"C","category":"Service Desk"},{"id":72,"question":"Which describes the utility of a service?","options":{"A":"A service that is fit for use","B":"A service that meets its service level targets","C":"A service that increases constraints on the consumer","D":"A service that supports the performance of the consumer"},"answer":"D","category":"General Concepts"},{"id":73,"question":"Which is included in the purpose of the 'service level management' practice?","options":{"A":"To maximize the number of successful service and product changes","B":"To ensure accurate information about the configuration of services is available","C":"To set clear business-based targets for service levels","D":"To ensure that suppliers and their performance are managed appropriately"},"answer":"C","category":"Service Level Management"},{"id":74,"question":"Which usually requires a team of representatives from many stakeholder groups?","options":{"A":"Fulfilling a service request","B":"Authorizing an emergency change","C":"Logging a new problem","D":"Investigating a major incident"},"answer":"D","category":"Change Enablement"},{"id":75,"question":"Which value chain activity ensures that service components meet agreed specifications?","options":{"A":"Plan","B":"Design and transition","C":"Obtain/build","D":"Deliver and support"},"answer":"C","category":"Service Value Chain"},{"id":76,"question":"What includes governance as a component?","options":{"A":"Practices","B":"The service value chain","C":"The service value system","D":"The guiding principles"},"answer":"C","category":"Guiding Principles"},{"id":77,"question":"Which practice needs people who understand complex systems and have creative and analytical skills?","options":{"A":"Change enablement","B":"Service level management","C":"Service request management","D":"Problem management"},"answer":"D","category":"Change Enablement"},{"id":78,"question":"What is the definition of a known error?","options":{"A":"An unplanned interruption to a service, or reduction in the quality of a service","B":"A cause, or potential cause, of one or more incident","C":"A problem that has been analyzed and has not been resolved","D":"Any change of state that has significance for the management of a service or other configuration item (CI)"},"answer":"C","category":"Problem Management"},{"id":79,"question":"Which guiding principle is PRIMARILY concerned with end-to-end service delivery?","options":{"A":"Focus on value","B":"Think and work holistically","C":"Optimize and automate","D":"Collaborate and promote visibility"},"answer":"B","category":"Guiding Principles"},{"id":80,"question":"What are typically recognized through notifications created by an IT service, CI or monitoring tool?","options":{"A":"Incidents","B":"Problems","C":"Events","D":"Requests"},"answer":"C","category":"Monitoring and Event Management"},{"id":81,"question":"Which dimension considers data security and privacy?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"B","category":"Four Dimensions of Service Management"},{"id":82,"question":"Which term relates to service levels aligned with the needs of service consumers?","options":{"A":"Service management","B":"Warranty","C":"Cost","D":"Utility"},"answer":"B","category":"General Concepts"},{"id":83,"question":"Which directly assists with the diagnosis and resolution of simple incidents?","options":{"A":"Scripts for collecting user information","B":"Use of shift working patterns","C":"Fulfilment of service requests","D":"Creation of a temporary team"},"answer":"A","category":"Service Request Management"},{"id":84,"question":"What are guiding principles?","options":{"A":"A set of interconnected activities that help an organization deliver a valuable service","B":"A description of one or more services that help address the needs of a target consumer group","C":"A set of specialized organizational capabilities for enabling value for customers","D":"Recommendations that help an organization when adopting a service management approach"},"answer":"D","category":"Guiding Principles"},{"id":85,"question":"Which approach is CORRECT when applying the guiding principle 'keep it simple and practical'?","options":{"A":"Only add controls and metrics when they are needed","B":"Design controls and metrics first, then remove those not adding value","C":"Design controls and metrics and add them individually until all are implemented","D":"Only add controls and metrics that are required for compliance"},"answer":"B","category":"Guiding Principles"},{"id":86,"question":"What is the purpose of the 'problem management' practice?","options":{"A":"To protect the information needed by the organization to conduct its business","B":"To reduce the likelihood and impact of incidents by identifying actual and potential causes of incidents, and managing workarounds and known errors","C":"To align the organization's practices and services with changing business needs through the ongoing identification and improvement of services","D":"To minimize the negative impact of incidents by restoring normal service operation as quickly as possible"},"answer":"B","category":"Problem Management"},{"id":87,"question":"Which practice forms a link between the service provider and the users of services?","options":{"A":"Change enablement","B":"Service level management","C":"Problem management","D":"Service desk"},"answer":"D","category":"Change Enablement"},{"id":88,"question":"Which is a purpose of release management?","options":{"A":"To protect the organization's information","B":"To handle user-initiated service requests","C":"To make new and changed services available for use","D":"To move hardware and software to live environments"},"answer":"C","category":"Service Request Management"},{"id":89,"question":"What is recommended by the guiding principle 'progress iteratively with feedback'?","options":{"A":"A current state assessment that is carried out at the start of an improvement initiative","B":"The identification of all interested parts at the start of an improvement initiative","C":"An improvement initiative that is broken into a number of manageable sections","D":"An assessment of how all the parts of an organization will affect an improvement initiative"},"answer":"C","category":"Guiding Principles"},{"id":90,"question":"Which guiding principle considers customer and user experience?","options":{"A":"Collaborate and promote visibility","B":"Focus on value","C":"Start where you are","D":"Keep it simple and practical"},"answer":"B","category":"Guiding Principles"},{"id":91,"question":"Which statement about the 'change enablement' practice is CORRECT?","options":{"A":"Service requests are usually normal changes that can be implemented quickly without authorization","B":"Emergency changes are changes that must be fully tested and fully documented prior to implementation","C":"Standard changes are changes that need to be scheduled, assessed and authorized following a standard process","D":"Emergency changes are changes that must be implemented as soon as possible and therefore authorization is expedited"},"answer":"D","category":"Change Enablement"},{"id":92,"question":"Which is a key activity carried out in the 'did we get there?' step of the 'continual improvement' model?","options":{"A":"Define measurable targets","B":"Perform baseline assessments","C":"Execute improvement actions","D":"Evaluate measurements and metrics"},"answer":"D","category":"Continual Improvement"},{"id":93,"question":"What can a service remove from the consumer and impose on the consumer?","options":{"A":"Utility","B":"Asset","C":"Cost","D":"Outcome"},"answer":"C","category":"General Concepts"},{"id":94,"question":"What does 'change enablement' PRIMARILY focus on?","options":{"A":"Changes to service levels","B":"Changes to products and services","C":"Changes to organizational structure","D":"Changes to skills and competencies"},"answer":"B","category":"Change Enablement"},{"id":95,"question":"Which is handled as a service request?","options":{"A":"An investigation to identify the cause of an incident","B":"A compliment about an IT support team","C":"The failure of an IT service","D":"An emergency change to implement a security patch"},"answer":"B","category":"Change Enablement"},{"id":96,"question":"Which is a key requirement for a successful service level agreement (SLA)?","options":{"A":"Using individual metrics that relate to the service catalogue","B":"Using bundled metrics to relate performance to outcomes","C":"Using single-system-based metrics that relate to outputs","D":"Using an agreement between the service provider and service supplier"},"answer":"B","category":"Service Level Management"},{"id":97,"question":"Which is considered by the 'partners and suppliers' dimension?","options":{"A":"Using artificial intelligence","B":"Defining controls and procedures","C":"Using formal roles and responsibilities","D":"Working with an integrator to manage relationships"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":98,"question":"Which practice recommends using tools for collaboration and the automated matching of symptoms?","options":{"A":"Problem management","B":"Service level management","C":"Incident management","D":"Service request management"},"answer":"C","category":"Incident Management"},{"id":99,"question":"Which practice would help a user gain access to an application that they need to use?","options":{"A":"Service configuration management","B":"Change enablement","C":"Service request management","D":"Service level management"},"answer":"C","category":"Change Enablement"},{"id":100,"question":"What is used to link activities within the service value chain?","options":{"A":"Service level agreements","B":"Inputs, outputs and triggers","C":"Opportunity, demand and value","D":"Service desk"},"answer":"B","category":"Service Value Chain"},{"id":101,"question":"Which two practices use workarounds?","options":{"A":"Change enablement and continual improvement","B":"Change enablement and problem management","C":"Problem management and incident management","D":"Incident management and continual improvement"},"answer":"C","category":"Continual Improvement"},{"id":102,"question":"Which is included in the purpose of the 'deliver and support' value chain activity?","options":{"A":"Meeting stakeholder expectations for time to market","B":"Understanding the organization's service vision","C":"Understanding stakeholder needs","D":"Providing services to agreed specifications"},"answer":"D","category":"Service Value Chain"},{"id":103,"question":"Which are elements of the service value system?","options":{"A":"Service provision, service consumption, service relationship management","B":"Governance, service value chain, practices","C":"Outcomes, utility, warranty","D":"Customer value, stakeholder value, organization"},"answer":"B","category":"Service Value Chain"},{"id":104,"question":"What is an incident?","options":{"A":"The planned removal of an item that might affect a service","B":"A result enabled by one or more outputs","C":"A possible future event that could cause harm","D":"A service interruption resolved by the use of self-help tools"},"answer":"D","category":"General Concepts"},{"id":105,"question":"What is defined as a change of state that has significance for the management of an IT service?","options":{"A":"Event","B":"Incident","C":"Problem","D":"Known error"},"answer":"A","category":"Problem Management"},{"id":106,"question":"Which dimension includes the knowledge needed for the management of services?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"B","category":"Four Dimensions of Service Management"},{"id":107,"question":"What is the PRIMARY use of a change schedule?","options":{"A":"To support the 'incident management' practice and improvement planning","B":"To manage emergency changes","C":"To plan changes and help avoid conflicts","D":"To manage standard changes"},"answer":"C","category":"Change Enablement"},{"id":108,"question":"Which guiding principle focuses on reducing costs and human errors?","options":{"A":"Focus on value","B":"Collaborate and promote visibility","C":"Optimize and automate","D":"Think and work holistically"},"answer":"C","category":"Guiding Principles"},{"id":109,"question":"Which guiding principle helps to ensure that each improvement effort has more focus and is easier to maintain?","options":{"A":"Start where you are","B":"Collaborate and promote visibility","C":"Progress iteratively with feedback","D":"Think and work holistically"},"answer":"C","category":"Guiding Principles"},{"id":110,"question":"Which is a key activity carried out in the 'did we get there?' step of the 'continual improvement' model?","options":{"A":"Define measurable targets","B":"Perform baseline assessments","C":"Execute improvement actions","D":"Evaluate measurements and metrics"},"answer":"D","category":"Continual Improvement"},{"id":111,"question":"What is important for a 'continual improvement register' (CIR)?","options":{"A":"Improvement ideas are documented, assessed and prioritized","B":"Improvement ideas from many sources are kept in a single CIR","C":"Improvement ideas that are not being actioned immediately are removed from the CIR","D":"Improvement ideas are tested, funded and agreed"},"answer":"A","category":"Continual Improvement"},{"id":112,"question":"Which is a purpose of the 'service level management' practice?","options":{"A":"To establish and nurture the links between the organization and its stakeholders","B":"To ensure that the organization's suppliers and their performance are managed appropriately","C":"To support the agreed quality of a service by handling all agreed, user-initiated service requests","D":"To set clear business-based targets for service levels"},"answer":"D","category":"Service Level Management"},{"id":113,"question":"What describes the steps needed to create and deliver a specific service to a consumer?","options":{"A":"Service management","B":"Practices","C":"A value stream","D":"Service level management"},"answer":"C","category":"Service Level Management"},{"id":114,"question":"Which helps to manage an incident when it is unclear which support team should be working on the incident?","options":{"A":"Disaster recovery plans","B":"Swarming","C":"Target resolution times","D":"Self-help"},"answer":"B","category":"General Concepts"},{"id":115,"question":"Which statement about the 'continual improvement' practice is CORRECT?","options":{"A":"Continual improvement participation should be limited to a small dedicated team","B":"It is the role of senior management to authorize improvement initiatives","C":"Training should be provided to those involved in continual improvement","D":"A single continual improvement register should be maintained by senior management"},"answer":"B","category":"Continual Improvement"},{"id":116,"question":"Which does the ITIL service value system discourage?","options":{"A":"Coordinated authorities and responsibilities","B":"Organizational silos","C":"Interfaces among practices","D":"Organizational agility"},"answer":"B","category":"Service Value System"},{"id":117,"question":"An SLA is a service level agreement. Which describes the 'watermelon SLA' effect?","options":{"A":"A single SLA defines target service levels for multiple customers, so every customer sees reports about other customers' experiences","B":"The metrics in an SLA are focused on internal measures, so that reports show everything is good, while the customer is not satisfied","C":"SLA targets change very frequently, so that each report includes new measures and trends cannot be analyzed","D":"Introducing SLAs for a service enables customers to see that the service provider is doing a really good job, so this improves satisfaction"},"answer":"B","category":"Service Level Management"},{"id":118,"question":"Which practice includes conducting regular reviews to ensure that services are still appropriate and relevant?","options":{"A":"Service level management","B":"Service desk","C":"Continual improvement","D":"Change enablement"},"answer":"A","category":"Continual Improvement"},{"id":119,"question":"What is a service?","options":{"A":"A possible event that could cause harm or loss, or make it more difficult to achieve objectives","B":"A means of enabling value co-creation by facilitating outcomes that customers want to achieve, without the customer having to manage specific costs and risks","C":"A tangible or intangible deliverable of an activity","D":"Joint activities performed by a service provider and a service consumer to ensure continual value co-creation based on agreed and available service offerings"},"answer":"B","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":120,"question":"Which TWO are important aspects of the 'service request management' practice? 1. Standardization and automation 2. Providing a variety of channels for access 3. Establishing a shared view of targets 4. Policies for approvals","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"D","category":"Service Request Management"},{"id":121,"question":"What is required by all service desk staff?","options":{"A":"Excellent technical knowledge","B":"Root cause analysis skills","C":"Demonstration of emotional intelligence","D":"Knowledge of telephony technology"},"answer":"C","category":"Service Desk"},{"id":122,"question":"Which practice establishes a channel between the service provider and its users?","options":{"A":"Relationship management","B":"Change enablement","C":"Supplier management","D":"Service desk"},"answer":"D","category":"Change Enablement"},{"id":123,"question":"Which practice includes the use of approaches such as Lean, Agile and DevOps with the aim of facilitating a greater amount of change at a quicker rate?","options":{"A":"Service desk","B":"Monitoring and event management","C":"Service level management","D":"Continual improvement"},"answer":"D","category":"Continual Improvement"},{"id":124,"question":"Which practice has a purpose that includes maximizing success by ensuring that risks have been properly assessed?","options":{"A":"Relationship management","B":"Change enablement","C":"Release management","D":"Monitoring and event management"},"answer":"B","category":"Change Enablement"},{"id":125,"question":"Which practice provides users with a way to get various requests arranged, explained and coordinated?","options":{"A":"Service level management","B":"Relationship management","C":"Continual improvement","D":"Service desk"},"answer":"D","category":"Continual Improvement"},{"id":126,"question":"Which helps to streamline the fulfilment of service requests?","options":{"A":"Understanding which service requests can be accomplished with limited approvals","B":"Creating new workflows for every service request","C":"Separating requests relating to service failures from the degradation of services","D":"Eliminating service requests which have complex workflows"},"answer":"A","category":"Service Request Management"},{"id":127,"question":"Which statement about outcomes is CORRECT?","options":{"A":"They are deliverables provided to service consumers","B":"They allow service consumers to achieve a desired result","C":"They provide products to service providers based on outputs","D":"They co-create value for service providers by reducing costs and risks"},"answer":"B","category":"General Concepts"},{"id":128,"question":"Which guiding principle says that services and processes should NOT provide a solution for every exception?","options":{"A":"Keep it simple and practical","B":"Collaborate and promote visibility","C":"Think and work holistically","D":"Optimize and automate"},"answer":"A","category":"Guiding Principles"},{"id":129,"question":"Identify the missing word in the following sentence. The purpose of the 'supplier management' practice is to ensure that the organization’s suppliers and their performances are [?] appropriately to support the seamless provision of quality products and services.","options":{"A":"measured","B":"rewarded","C":"managed","D":"defined"},"answer":"C","category":"Supplier Management"},{"id":130,"question":"Identify the missing words in the following sentence. The purpose of the service configuration management practice is to ensure that accurate and reliable information about the [?], and the CIs that support them, is available when and where it is needed.","options":{"A":"relationships with suppliers","B":"configuration of services","C":"skills of people","D":"authorization of changes"},"answer":"B","category":"Service Configuration Management"},{"id":131,"question":"Which practice requires skills and competencies related to business analysis, supplier management and relationship management?","options":{"A":"Incident management","B":"Monitoring and event management","C":"Service level management","D":"IT asset management"},"answer":"C","category":"Incident Management"},{"id":132,"question":"When should a workaround be created?","options":{"A":"As soon as possible, once the incident is logged","B":"After the resolution of a problem","C":"When a problem cannot be resolved quickly","D":"When a potential permanent solution has been identified"},"answer":"C","category":"Problem Management"},{"id":133,"question":"What is a configuration item?","options":{"A":"Any financially valuable component that can contribute to the delivery of an IT product or service","B":"Any change of state that has significance for the management of a service","C":"Any component that needs to be managed in order to deliver an IT service","D":"A problem that has been analyzed but has not been resolved"},"answer":"C","category":"Service Configuration Management"},{"id":134,"question":"Identify the missing words in the following sentence. When an organization has decided to improve a service, it should start by considering [?].","options":{"A":"existing information","B":"new methods","C":"additional measurements","D":"revised processes"},"answer":"A","category":"General Concepts"},{"id":135,"question":"Which is a use of the change schedule?","options":{"A":"Assigning resources to changes","B":"Deciding the approval authority for changes","C":"Automating the change process","D":"Creating change models"},"answer":"A","category":"General Concepts"},{"id":136,"question":"Which dimension of service management considers the workflows and controls needed to deliver services?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":137,"question":"Which guiding principle considers how the steps of a process can be performed as efficiently as possible?","options":{"A":"Focus on value","B":"Start where you are","C":"Think and work holistically","D":"Optimize and automate"},"answer":"D","category":"Guiding Principles"},{"id":138,"question":"Which statement about the 'incident management' practice is CORRECT?","options":{"A":"It identifies the cause of major incidents","B":"It authorizes changes to resolve incidents","C":"It maintains detailed procedures for diagnosing incidents","D":"It resolves the highest impact incidents first"},"answer":"D","category":"Incident Management"},{"id":139,"question":"How should an organization prioritize incidents?","options":{"A":"Ask the user for their preferred resolution timeframe","B":"Assess the availability of the appropriate support team","C":"Use an agreed classification which is based on the business impact of the incident","D":"Create an order of incidents based on the dates and times when they were logged"},"answer":"C","category":"General Concepts"},{"id":140,"question":"Which is a purpose of the 'relationship management' practice?","options":{"A":"To systematically observe services and service components","B":"To protect the information needed by the organization to conduct its business","C":"To be the entry point and single point of contact for the service provider with all of its users","D":"To identify, analyze, monitor, and continually improve links with stakeholders"},"answer":"D","category":"Relationship Management"},{"id":141,"question":"Which statement about problems is CORRECT?","options":{"A":"Problems are not related to incidents","B":"Problems must be resolved quickly in order to restore normal business activity","C":"Problem analysis should focus on one of the four dimensions to achieve a fast diagnosis","D":"Problem prioritization involves risk assessment"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":142,"question":"Which is a risk that might be removed from a service consumer by an IT service?","options":{"A":"Service provider ceasing to trade","B":"Security breach","C":"Failure of server hardware","D":"Cost of purchasing servers"},"answer":"B","category":"General Concepts"},{"id":143,"question":"Which is one of the MAIN concerns of the 'design and transition' value chain activity?","options":{"A":"Understanding the organization's vision","B":"Understanding stakeholder needs","C":"Meeting stakeholder expectations","D":"Ensuring service components are available"},"answer":"C","category":"Service Value Chain"},{"id":144,"question":"Which should be handled by 'service request management'?","options":{"A":"A request to implement a security patch","B":"A request to provide a laptop","C":"A request to resolve an error in a service","D":"A request to change a target in a service level agreement"},"answer":"B","category":"Service Level Management"},{"id":145,"question":"What can be described as an operating model for the creation and management of products and services?","options":{"A":"Governance","B":"Service value chain","C":"Guiding principles","D":"Practices"},"answer":"B","category":"Guiding Principles"},{"id":146,"question":"Which action is performed by a service provider?","options":{"A":"Requesting required service actions","B":"Authorizing budget for service consumption","C":"Ensuring access to agreed resources","D":"Receiving of the agreed goods"},"answer":"C","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":147,"question":"Which step of the continual improvement model includes baseline assessments?","options":{"A":"Did we get there?","B":"Where are we now?","C":"What is the vision?","D":"Where do we want to be?"},"answer":"B","category":"Continual Improvement"},{"id":148,"question":"Which describes a 'change authority'?","options":{"A":"A model used to determine who will assess a change","B":"A person who approves a change","C":"A tool used to help plan changes","D":"A way to manage the people aspects of change"},"answer":"B","category":"Change Enablement"},{"id":149,"question":"Which is NOT a component of the service value system?","options":{"A":"The service value chain","B":"Opportunity and demand","C":"Continual improvement","D":"Governance"},"answer":"B","category":"Service Value Chain"},{"id":150,"question":"Which statement about service relationship management is CORRECT?","options":{"A":"It focuses on the service actions performed by users","B":"It requires the service consumer to create resources for the service provider","C":"It requires co-operation of both the service provider and service consumer","D":"It focuses on the fulfilment of the agreed service actions"},"answer":"C","category":"Relationship Management"},{"id":151,"question":"What is the MOST important reason for prioritizing incidents?","options":{"A":"To ensure that user expectations are realistic","B":"To ensure that incidents with highest impact are resolved first","C":"To help information-sharing and learning","D":"To provide links to related changes and known errors"},"answer":"B","category":"Problem Management"},{"id":152,"question":"Which 'service level management' activity helps staff to deliver a more business-focused service?","options":{"A":"Creating targets based on the percentage of uptime of a service","B":"Understanding the ongoing requirements of customers","C":"Using complex technical terminology in service level agreements (SLAs)","D":"Measuring low-level operational activities"},"answer":"B","category":"Service Level Management"},{"id":153,"question":"Which practice has a purpose that includes the handling of pre-defined, user-initiated demands for service?","options":{"A":"Service request management","B":"Service configuration management","C":"Deployment management","D":"Change enablement"},"answer":"A","category":"Change Enablement"},{"id":154,"question":"Which guiding principle considers which parts of an existing process should be kept by identifying how they contribute to value creation?","options":{"A":"Progress iteratively with feedback","B":"Collaborate and promote visibility","C":"Think and work holistically","D":"Keep it simple and practical"},"answer":"D","category":"Guiding Principles"},{"id":155,"question":"What is the purpose of the 'monitoring and event management' practice?","options":{"A":"To restore normal service operation as quickly as possible","B":"To manage workarounds and known errors","C":"To capture demand for incident resolution and service requests","D":"To systematically observe services and service components"},"answer":"D","category":"Problem Management"},{"id":156,"question":"Which statement about outcomes is CORRECT?","options":{"A":"Outcomes rely on outputs to deliver results for a stakeholder","B":"Outcomes use activities to produce tangible or intangible deliverables","C":"Outcomes give service consumers assurance of products or services","D":"Outcomes help a service consumer to assess the cost of a specific activity"},"answer":"A","category":"General Concepts"},{"id":157,"question":"Which skill is required by the 'service level management' practice?","options":{"A":"Supplier management","B":"Technical expertise","C":"Event monitoring","D":"Problem management"},"answer":"A","category":"Problem Management"},{"id":158,"question":"Which statement about the 'continual improvement model' is CORRECT?","options":{"A":"Organizations should work through the steps of the model in the sequence in which they are presented","B":"The flow of the model helps organizations to link improvements to its goals","C":"The model is applicable to only certain parts of the service value system","D":"Organizations should use an additional model or method to link improvements to customer value"},"answer":"A","category":"Service Value System"},{"id":159,"question":"What is the definition of warranty?","options":{"A":"A means of identifying events that could cause harm or loss","B":"A means of determining whether a service is fit for purpose","C":"A means of identifying a result for a stakeholder","D":"A means of determining whether a service is fit for use"},"answer":"D","category":"General Concepts"},{"id":160,"question":"Which practice has a purpose that includes managing risks relating to confidentiality, integrity and availability?","options":{"A":"Change enablement","B":"Problem management","C":"Information security management","D":"Service configuration management"},"answer":"C","category":"Change Enablement"},{"id":161,"question":"Which statement about value creating activities is CORRECT?","options":{"A":"Each value stream should be designed with a specific combination of service value chain activities","B":"Service value chain activities have pre-determined dependencies on ITIL practices","C":"A value stream is an operating model for creating value through products and services","D":"Organizations should ensure that each value stream is applicable to many scenarios"},"answer":"A","category":"Service Value Chain"},{"id":162,"question":"Which is provided by the 'engage' value chain activity?","options":{"A":"Ensuring that stakeholder expectations for quality are met","B":"Ensuring that stakeholder needs are understood by the organization","C":"Ensuring that service components are available when needed","D":"Ensuring that services are operated to meet agreed specifications"},"answer":"B","category":"Service Value Chain"},{"id":163,"question":"Which is part of the 'focus on value' guiding principle?","options":{"A":"Understanding what services help the service consumer","B":"Reducing the number of steps in the customer experience","C":"Assessing services to identify parts that can be reused","D":"Identifying activities that can be achieved in smaller iterations"},"answer":"A","category":"Guiding Principles"},{"id":164,"question":"Which is part of the definition of a customer?","options":{"A":"The role that defines the requirements for a service","B":"A means of enabling value co-creation","C":"The role that authorizes budget for service consumption","D":"A set of specialized organizational capabilities for enabling value"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":165,"question":"Which guiding principle helps an organization to understand the impact of an altered element on other elements in a system?","options":{"A":"Focus on value","B":"Start where you are","C":"Think and work holistically","D":"Keep it simple and practical"},"answer":"C","category":"Guiding Principles"},{"id":166,"question":"Identify the missing words in the following sentence: The 'incident management' practice should maintain [?] for logging and managing incidents.","options":{"A":"a dedicated team","B":"a formal process","C":"detailed procedures","D":"a value chain activity"},"answer":"C","category":"Service Value Chain"},{"id":167,"question":"What is the purpose of the 'deployment management' practice?","options":{"A":"To make new and changed services and features available for use","B":"To move new or changed components to live environments","C":"To plan and manage the full lifecycle of all IT assets","D":"To protect the information needed by the organization to conduct its business"},"answer":"B","category":"Deployment Management"},{"id":168,"question":"Which TWO statements about the guiding principles are CORRECT? 1. The guiding principles support continual improvement 2. Each guiding principle applies to a selection of the available stakeholder groups 3. Organizations should decide which one of the guiding principles is relevant to them 4. Organizations should consider how the guiding principles interact with each other","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"D","category":"Guiding Principles"},{"id":169,"question":"Which is an activity of 'problem identification'?","options":{"A":"Analyzing information from software developers","B":"Establishing problem workarounds","C":"Analyzing the cause of problems","D":"Establishing potential permanent solutions"},"answer":"A","category":"Problem Management"},{"id":170,"question":"Which practice uses technologies such as intelligent telephony systems, a knowledge base and monitoring tools?","options":{"A":"Service configuration management","B":"Service desk","C":"Problem management","D":"Deployment management"},"answer":"B","category":"Problem Management"},{"id":171,"question":"Which statement about standard changes is CORRECT?","options":{"A":"A full assessment should be completed each time the change is implemented","B":"The change can be implemented with less testing if necessary","C":"The appropriate change authority should be assigned to each type of change","D":"The change does not require additional authorization"},"answer":"D","category":"Change Enablement"},{"id":172,"question":"Which TWO are considered part of the 'organizations and people' dimension of service management? 1. Systems of authority 2. Culture 3. Relationships between organizations 4. Workflows","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"A","category":"Four Dimensions of Service Management"},{"id":173,"question":"Which statement about the 'service request management' practice is CORRECT?","options":{"A":"Service requests are fulfilled using simple workflows","B":"A new workflow is created for each type of request","C":"Additional approval is sometimes needed for restoration of service","D":"Financial authorization is sometimes required for service requests"},"answer":"A","category":"Service Request Management"},{"id":174,"question":"What is a cause, or potential cause, of one or more incidents?","options":{"A":"A problem","B":"A configuration item","C":"A workaround","D":"An incident"},"answer":"A","category":"Problem Management"},{"id":175,"question":"Which guiding principle says that it is not usually necessary to build something new?","options":{"A":"Focus on value","B":"Start where you are","C":"Progress iteratively with feedback","D":"Think and work holistically"},"answer":"B","category":"Guiding Principles"},{"id":176,"question":"Which practice includes management of workarounds and known errors?","options":{"A":"Monitoring and event management","B":"Service configuration management","C":"Problem management","D":"Incident management"},"answer":"C","category":"Incident Management"},{"id":177,"question":"Which activity is part of the 'continual improvement' practice?","options":{"A":"Handling compliments and complaints from users to identify improvements","B":"Improving relationships with and between stakeholders","C":"Prioritizing and creating business cases for improvement initiatives","D":"Identifying the cause of unplanned interruptions to service"},"answer":"C","category":"Continual Improvement"},{"id":178,"question":"Identify the missing word in the following sentence: A service is a means of enabling value co-creation by facilitating [?] that customers want to achieve, without the customer having to manage specific costs and risks.","options":{"A":"utility","B":"warranty","C":"outcomes","D":"outputs"},"answer":"C","category":"General Concepts"},{"id":179,"question":"Which is a low risk change that has been pre-approved so that no additional authorization is needed?","options":{"A":"A standard change","B":"A change model","C":"An emergency change","D":"A normal change"},"answer":"A","category":"Change Enablement"},{"id":180,"question":"Which describes the 'plan' value chain activity?","options":{"A":"It ensures a shared understanding of the current status and vision for all products and services across the organization","B":"It ensures that services are delivered and supported according to agreed specifications and stakeholders’ expectations","C":"It ensures that service components are available when and where they are needed, and meet agreed specifications","D":"It ensures continual improvement of products, services, and practices across all value chain activities"},"answer":"A","category":"Service Value Chain"},{"id":181,"question":"Which phase of problem management includes analyzing incidents to look for patterns and trends?","options":{"A":"Problem identification","B":"Problem control","C":"Error control","D":"Post-implementation review"},"answer":"A","category":"Problem Management"},{"id":182,"question":"Which statement about the 'optimize and automate' guiding principle is CORRECT?","options":{"A":"Activities should be automated before they are optimized","B":"Automation is best applied to non-standard tasks","C":"Technology eliminates the need for human intervention","D":"Automation frees human resources for more complex activities"},"answer":"C","category":"Guiding Principles"},{"id":183,"question":"What is defined as any financially valuable component that can contribute to the delivery of a service?","options":{"A":"Configuration item","B":"Product","C":"IT asset","D":"Event"},"answer":"C","category":"Service Configuration Management"},{"id":184,"question":"Which MOST helps an organization adapt ITIL concepts so that they apply to the organization's specific circumstances?","options":{"A":"Continual improvement","B":"Service value chain","C":"Practices","D":"Guiding principles"},"answer":"A","category":"Guiding Principles"},{"id":185,"question":"What is the MAIN benefit of 'problem management'?","options":{"A":"Restoring normal service as quickly as possible","B":"Reducing the number and impact of incidents","C":"Maximizing the number of successful changes","D":"Managing workarounds and known errors"},"answer":"D","category":"Problem Management"},{"id":186,"question":"Which guiding principle discourages 'silo activity'?","options":{"A":"Focus on value","B":"Start where you are","C":"Collaborate and promote visibility","D":"Keep it simple and practical"},"answer":"C","category":"Guiding Principles"},{"id":187,"question":"What is included in the purpose of the ‘relationship management’ practice?","options":{"A":"Identifying, analyzing, monitoring, and the continual improvement of relationships with stakeholders","B":"Setting clear business-based targets so that the delivery of a service can be properly assessed","C":"Creating collaborative relationships with key suppliers to uncover and realize new value","D":"Handling all pre-defined, user-initiated service requests in an effective and user-friendly manner"},"answer":"A","category":"Continual Improvement"},{"id":188,"question":"Which practice facilitates operational communication between the service provider organization and users in the service consumer organization?","options":{"A":"Service level management","B":"Relationship management","C":"Service desk","D":"Monitoring and event management"},"answer":"C","category":"Service Desk"},{"id":189,"question":"Which dimension considers the application of artificial intelligence to service management?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"B","category":"Four Dimensions of Service Management"},{"id":190,"question":"Which type of change is MOST LIKELY to be initiated as part of the 'service request management' practice?","options":{"A":"A normal change","B":"An emergency change","C":"A standard change","D":"A change model"},"answer":"C","category":"Change Enablement"},{"id":191,"question":"Which benefit is MOST aligned with the guiding principle 'progress iteratively with feedback'?","options":{"A":"Service providers are able to respond more quickly to customer needs","B":"Bottlenecks in the service provider's workflow are identified","C":"The complexities of the service provider's IT systems are identified","D":"The service provider gains a better understanding of the customer experience"},"answer":"A","category":"Guiding Principles"},{"id":192,"question":"Which costs are included in the value proposition of a service?","options":{"A":"Additional expense that the service consumer has because they are using the service","B":"Money that the service consumer no longer needs to spend because they are using the service","C":"Tangible or intangible results for the service consumer because they are using the service","D":"The benefits, usefulness, and importance of the service that are perceived by the service consumer"},"answer":"A","category":"General Concepts"},{"id":193,"question":"Identify the missing word in the following sentence: A [?] is the addition, modification, or removal of anything that could have a direct or indirect effect on services.","options":{"A":"problem","B":"risk","C":"change","D":"configuration item"},"answer":"C","category":"Service Configuration Management"},{"id":194,"question":"Which of the four dimensions includes the knowledge bases needed to deliver and manage services?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"B","category":"Four Dimensions of Service Management"},{"id":195,"question":"Staff in an IT organization are very busy, mostly carrying out tasks that add little or no value to the organization or its customers. Which guiding principle recommends that the unnecessary work should be eliminated?","options":{"A":"Keep it simple and practical","B":"Think and work holistically","C":"Start where you are","D":"Progress iteratively with feedback"},"answer":"A","category":"Guiding Principles"},{"id":196,"question":"Which practice has a purpose that includes the management of financially valuable components that can contribute to the delivery of an IT service?","options":{"A":"Deployment management","B":"Continual improvement","C":"Monitoring and event management","D":"IT asset management"},"answer":"D","category":"Continual Improvement"},{"id":197,"question":"Which practice ensures that service actions, that are a normal part of service delivery, are effectively handled?","options":{"A":"Incident management","B":"Service level management","C":"Problem management","D":"Service request management"},"answer":"B","category":"Incident Management"},{"id":198,"question":"A service will be unavailable for the next two hours for unplanned maintenance. Which practice is MOST LIKELY to be involved in managing this?","options":{"A":"Incident management","B":"Problem management","C":"Change enablement","D":"Service request management"},"answer":"A","category":"Change Enablement"},{"id":199,"question":"Which practice is MOST associated with the use of empathy to understand users?","options":{"A":"Service desk","B":"Continual improvement","C":"Service level management","D":"Change enablement"},"answer":"A","category":"Continual Improvement"},{"id":200,"question":"Identify the missing word in the following sentence: A customer defines the [?] for a service and takes responsibility for the outcomes of service consumption.","options":{"A":"requirements","B":"resources","C":"suppliers","D":"products"},"answer":"A","category":"Supplier Management"},{"id":201,"question":"Which of the following ensures that a service provider and a service consumer continually co- create value?","options":{"A":"Service consumption","B":"Service offerings","C":"Service level management","D":"Service relationship management"},"answer":"D","category":"Service Level Management"},{"id":202,"question":"What type of charge is often used for resolving incidents or implementing security patches?","options":{"A":"Standard change","B":"Normal change","C":"Emergency change","D":"Change model"},"answer":"C","category":"Change Enablement"},{"id":203,"question":"Which of the following includes configuring components and activities to facilitate outcomes for stakeholders?","options":{"A":"Service relationship management","B":"Service consumption","C":"The service value system","D":"The 'release management' practice"},"answer":"C","category":"Service Value System"},{"id":204,"question":"Which statement about outcomes is CORRECT?","options":{"A":"Outcomes enable products to be delivered to a stakeholder","B":"An outcome defines the amount of money spent on technology for a service","C":"An outcome depends on at least one output to deliver a result","D":"Outcomes provide assurance to stakeholders on how a service performs"},"answer":"C","category":"General Concepts"},{"id":205,"question":"Which phase of problem management includes the regular re-assessment of the effectiveness of workarounds?","options":{"A":"Problem identification","B":"Problem control","C":"Error control","D":"Problem analysis"},"answer":"C","category":"Problem Management"},{"id":206,"question":"Which practice performs reviews to ensure that services continue to meet the needs of the customers?","options":{"A":"Monitoring and event management","B":"Service level management","C":"Change enablement","D":"Service desk"},"answer":"B","category":"Change Enablement"},{"id":207,"question":"Which service value chain activity deals with the purchase of new products?","options":{"A":"Engage","B":"Obtain/build","C":"Plan","D":"Improve"},"answer":"B","category":"Service Value Chain"},{"id":208,"question":"Which of the following is included in the purpose of the 'continual improvement' practice?","options":{"A":"The restoration of normal service operation as quickly as possible","B":"The establishment of links between the organization and its stakeholders at strategic and tactical levels","C":"The alignment of the organization's practices and services with changing business needs","D":"The reduction of the likelihood and impact of incidents"},"answer":"C","category":"Continual Improvement"},{"id":209,"question":"Which is included in the purpose of the 'improve' value chain activity?","options":{"A":"Ensuring the continual improvement of practices across all value chain activities","B":"Ensuring that services continually meet expectations for quality, costs, and time to market","C":"Ensuring a shared understanding of the improvement direction for services across the organization","D":"Ensuring continual engagement and good relationships with all stakeholders"},"answer":"A","category":"Service Value Chain"},{"id":210,"question":"Which is the BEST type of resource for investigating complex incidents?","options":{"A":"Self-help systems","B":"Knowledgeable support staff","C":"Detailed work instructions","D":"Disaster recovery plans"},"answer":"B","category":"General Concepts"},{"id":211,"question":"What is defined as “any component that needs to be managed in order to deliver an IT service\"?","options":{"A":"An event","B":"An IT asset","C":"A configuration item","D":"A change"},"answer":"C","category":"Service Configuration Management"},{"id":212,"question":"Which TWO of the following statements are MOST associated with the 'optimize and automate' guiding principle? 1. It is important to assess which method of communication is appropriate for each type of stakeholder. 2. Complex systems should be designed with an understanding of how the components' parts are related. 3. Organizations should consider whether technology could improve the efficiency of manual processes. 4. It is important to understand the organization's objectives when assessing the impact of potential improvements","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"C","category":"Guiding Principles"},{"id":213,"question":"Which statement about emergency changes is CORRECT?","options":{"A":"Emergency changes are low risk and well understood","B":"Authorization of emergency changes may be deferred until after implementation","C":"It is necessary to complete all documentation before an emergency change is implemented","D":"Emergency changes are not usually recorded in the change schedule"},"answer":"D","category":"Change Enablement"},{"id":214,"question":"Which is the definition of an IT asset?","options":{"A":"Any financially valuable component that contributes to a service","B":"Any request from a user that is a normal part of service delivery","C":"Any component that needs to be managed to deliver a service","D":"Any change of state that has significance for the management of a service"},"answer":"A","category":"General Concepts"},{"id":215,"question":"Which dimension of service management includes consideration of the type of relationship required with other organizations involved in the design and delivery of services?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"C","category":"Four Dimensions of Service Management"},{"id":216,"question":"What is defined as 'the role that uses services'?","options":{"A":"Service consumer","B":"Customer","C":"User","D":"Sponsor"},"answer":"C","category":"General Concepts"},{"id":217,"question":"Which is an example of a problem control activity?","options":{"A":"Reviewing incident records to identify trends","B":"Implementing a technical fix to resolve an issue","C":"Re-assessing a known error to understand the ongoing impact","D":"Documenting the steps in a workaround"},"answer":"D","category":"Problem Management"},{"id":218,"question":"What should remain constant within an organization, even when the organizations objectives change?","options":{"A":"Outputs","B":"Guiding principles","C":"Service offerings","D":"Outcomes"},"answer":"B","category":"Guiding Principles"},{"id":219,"question":"Which is a key element of the 'think and work holistically' guiding principle?","options":{"A":"Assessing which procedures can be re-used when improving a service","B":"Understanding the methods applicable to complex systems","C":"Eliminating metrics which do not contribute to achieving an objective","D":"Using technology for standard tasks to give people time for complex activities"},"answer":"B","category":"Guiding Principles"},{"id":220,"question":"Which practice has a purpose that includes managing authentication and non-repudiation?","options":{"A":"Information security management","B":"Supplier management","C":"Service configuration management","D":"Relationship management"},"answer":"A","category":"Service Configuration Management"},{"id":221,"question":"Which of the following is the MOST important for effective incident management?","options":{"A":"Collaboration tools and techniques","B":"Balanced scorecard review","C":"Automated pipelines","D":"A variety of access channels"},"answer":"A","category":"Incident Management"},{"id":222,"question":"Which practice handles all pre-defined user-initiated service actions?","options":{"A":"Deployment management","B":"Incident management","C":"Service level management","D":"Service request management"},"answer":"D","category":"Incident Management"},{"id":223,"question":"Which is the MOST important stakeholder group that a service provider needs to collaborate with?","options":{"A":"Suppliers","B":"Customers","C":"Relationship managers","D":"Developers"},"answer":"C","category":"Supplier Management"},{"id":224,"question":"Which activity is NOT recommended by the 'start where you are' guiding principle?","options":{"A":"Involving people who are not familiar with a service when observing and assessing its activities","B":"Applying risk management when considering to introduce new processes","C":"Using source data to avoid any unintentional data distortion round in reports","D":"Discarding existing processes before assessing their usefulness"},"answer":"D","category":"Guiding Principles"},{"id":225,"question":"For which purpose would the continual improvement practice use a SWOT analysis?","options":{"A":"Understanding the current state","B":"Defining the future desired state","C":"Tracking and managing ideas","D":"Ensuring everyone actively participates"},"answer":"A","category":"Continual Improvement"},{"id":226,"question":"Which TWO types of competence are MOST important for service desk staff? 1. Knowledge of business processes 2. Collaboration skills 3. Advanced technical knowledge 4. Workflow design skills","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"A","category":"Service Desk"},{"id":227,"question":"Which is CORRECT about change authorization?","options":{"A":"A change authority is assigned each time a standard change is requested","B":"Emergency changes are authorized by the technician making the change","C":"Assignment of the change authority is based on the change type and model","D":"The change authority will ensure changes are authorized after they are deployed"},"answer":"C","category":"Change Enablement"},{"id":228,"question":"What term is used to describe the functionality of a service?","options":{"A":"Output","B":"Outcome","C":"Utility","D":"Warranty"},"answer":"C","category":"General Concepts"},{"id":229,"question":"Which practice ensures that a variety of access channels are available for users to report issues?","options":{"A":"Service desk","B":"Service level management","C":"Incident management","D":"Change enablement"},"answer":"A","category":"Change Enablement"},{"id":230,"question":"Identify the missing word(s) in the following sentence: The purpose of the problem management practice is to reduce the likelihood and impact of incidents by identifying actual and potential causes of incidents, and managing workarounds and [?].","options":{"A":"events","B":"changes","C":"IT assets","D":"known errors"},"answer":"D","category":"Problem Management"},{"id":231,"question":"Which is a key requirement for a successful service level agreements (SLAs)?","options":{"A":"They should be written using language and terms which all parties will understand","B":"They should be based on system-based metrics which are useful to the service provider","C":"They should be carried forward, unchanged, from one year to the next to enable consistent service","D":"They should avoid ambiguous targets such as those relating to user experience"},"answer":"A","category":"Service Level Management"},{"id":232,"question":"Which is an example of a service request?","options":{"A":"A request for normal operation to be restored","B":"A request to implement a security patch","C":"A request for access to a file","D":"A request to investigate the cause of an incident"},"answer":"C","category":"Service Request Management"},{"id":233,"question":"Which of the four dimensions focuses on managing data in compliance with industry regulations?","options":{"A":"Partners and suppliers","B":"Organizations and people","C":"Value streams and processes","D":"Information and technology"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":234,"question":"When using the ITIL continual improvement model, which information should be produced by an organization in order to understand where the organization is now?","options":{"A":"Business objectives","B":"Improvement plans","C":"Assessment results","D":"KPI reports"},"answer":"C","category":"Continual Improvement"},{"id":235,"question":"Which guiding principle leads to a faster response to customer needs by timeboxing activities and learning from the outputs of previous activities?","options":{"A":"Focus on value","B":"Progress iteratively with feedback","C":"Collaborate and promote visibility","D":"Optimize and automate"},"answer":"B","category":"Guiding Principles"},{"id":236,"question":"Which practice has a purpose that includes maximizing the number of successful additions, modifications, or removals of anything that could have an effect on a service?","options":{"A":"Service request management","B":"Incident management","C":"Service desk","D":"Change enablement"},"answer":"D","category":"Change Enablement"},{"id":237,"question":"In which situation will incident management USUALLY use a separate process?","options":{"A":"Where no target resolution time exists","B":"For low impact incidents","C":"Where the cause must be diagnosed","D":"For information security incidents"},"answer":"D","category":"Incident Management"},{"id":238,"question":"Which practice minimizes the impact on normal service operation by managing resources in response to unplanned reductions in service quality?","options":{"A":"Incident management","B":"Change enablement","C":"Service level management","D":"Continual improvement"},"answer":"A","category":"Continual Improvement"},{"id":239,"question":"Which practice makes use of methods from Lean, Agile and DevOps?","options":{"A":"Service desk","B":"Continual improvement","C":"Problem management","D":"Incident management"},"answer":"B","category":"Continual Improvement"},{"id":240,"question":"Identify the missing word in the following sentence: Sponsor is the role that authorizes budget for service [?].","options":{"A":"value","B":"consumption","C":"management","D":"provision"},"answer":"B","category":"General Concepts"},{"id":241,"question":"Which statement about service offerings is CORRECT?","options":{"A":"The same product can be used as a basis for more than one service offering","B":"Service offerings include the transfer of goods from the consumer to the provider","C":"Service offerings describe how providers and consumers cooperate to co-create value","D":"Each service should be described to consumers as a single service offering"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":242,"question":"Which can a change schedule be used for?","options":{"A":"Speeding up the planning and authorization of emergency changes","B":"Providing information about deployed changes to help manage incidents and problems","C":"Providing a means of initiating and assessing normal changes","D":"Tracking and managing improvement ideas from identification through to final action"},"answer":"B","category":"Change Enablement"},{"id":243,"question":"Which is part of the value proposition of a service?","options":{"A":"Costs removed from the consumer by the service","B":"Costs imposed on the consumer by the service","C":"Outputs of the service received by the consumer","D":"Risks imposed on the consumer by the service"},"answer":"A","category":"General Concepts"},{"id":244,"question":"Why should a service level manager carry out regular service reviews?","options":{"A":"To ensure that agreements are written simply and are easy to understand","B":"To collect information about service consumer goals and objectives","C":"To capture information about service issues and performance against agreed goals","D":"To ensure continual improvement of services, so that they meet the evolving needs of service consumers"},"answer":"C","category":"Continual Improvement"},{"id":245,"question":"A flaw in an application could cause a service to fail. IT staff are actively analyzing the application to try and understand what is going on. What is the correct name for this type of flaw?","options":{"A":"Problem","B":"Incident","C":"Event","D":"Known error"},"answer":"A","category":"Problem Management"},{"id":246,"question":"Which value chain activity ensures that ongoing service activity meets user expectations?","options":{"A":"Plan","B":"Engage","C":"Obtain/build","D":"Deliver and support"},"answer":"D","category":"Service Value Chain"},{"id":247,"question":"Which practice’s purpose includes creating closer, more collaborative relationships?","options":{"A":"Supplier management","B":"Information security management","C":"Release management","D":"Service configuration management"},"answer":"A","category":"Release Management"},{"id":248,"question":"Which TWO are inputs to the service value system? 1. Demand 2. Products 3. Value 4. Opportunity","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"D","category":"Service Value System"},{"id":249,"question":"What role would be MOST suitable for someone with experience of managing relationships with various stakeholders, including suppliers and business managers?","options":{"A":"Service level manager","B":"Service desk agent","C":"Change authority","D":"Problem analyst"},"answer":"A","category":"Change Enablement"},{"id":250,"question":"Which is the addition, modification or removal of anything that could have an effect on services?","options":{"A":"A change","B":"An event","C":"A service request","D":"A problem"},"answer":"A","category":"Service Request Management"},{"id":251,"question":"Which guiding principle recommends consideration of the four dimensions in order to make something as effective and as useful as it needs to be?","options":{"A":"Focus on value","B":"Start where you are","C":"Think and work holistically","D":"Optimize and automate"},"answer":"D","category":"Guiding Principles"},{"id":252,"question":"Which practice is MOST LIKELY to make use of artificial intelligence, robotic process automation, and chatbots?","options":{"A":"Service desk","B":"Continual improvement","C":"Problem management","D":"Incident management"},"answer":"A","category":"Continual Improvement"},{"id":253,"question":"What is a problem that has been analyzed but has not been resolved?","options":{"A":"Workaround","B":"Incident","C":"Known error","D":"Risk"},"answer":"C","category":"Problem Management"},{"id":254,"question":"Which is described by the 'organizations and people' dimension of service management?","options":{"A":"Workflows and controls","B":"Communication and collaboration","C":"Inputs and outputs","D":"Contracts and agreements"},"answer":"B","category":"Four Dimensions of Service Management"},{"id":255,"question":"Which facilitates outcomes that customers want to achieve?","options":{"A":"Service","B":"Warranty","C":"Organization","D":"IT asset"},"answer":"A","category":"General Concepts"},{"id":256,"question":"Which practice recommends that organizations develop competencies in techniques such as strength, weakness, opportunity, and threat (SWOT) analysis, and balanced scorecards?","options":{"A":"Incident management","B":"Continual improvement","C":"Service request management","D":"Change enablement"},"answer":"B","category":"Continual Improvement"},{"id":257,"question":"Which ITIL concept helps an organization to make good decisions?","options":{"A":"Four dimensions of service management","B":"Guiding principles","C":"Service value chain","D":"Practices"},"answer":"B","category":"Guiding Principles"},{"id":258,"question":"Which is a recommendation applying the guiding principle 'keep it simple and practical'?","options":{"A":"Communicate in a way the audience can hear","B":"Sometimes nothing from the current state can be re-used","C":"If a practice is easier to follow it is more likely to be adopted","D":"Fast does not mean incomplete"},"answer":"C","category":"Guiding Principles"},{"id":259,"question":"Which practice has a purpose that includes responding to conditions that could lead to potential faults or incidents?","options":{"A":"Incident management","B":"Service request management","C":"Monitoring and event management","D":"Change enablement"},"answer":"C","category":"Change Enablement"},{"id":260,"question":"What role would be MOST suitable for a new graduate with great levels of empathy and understanding of business issues?","options":{"A":"Service level manager","B":"Service desk agent","C":"Change authority","D":"Problem analyst"},"answer":"B","category":"Change Enablement"},{"id":261,"question":"Which practice nurtures links with stakeholders at strategic and tactical levels?","options":{"A":"Supplier management","B":"Relationship management","C":"Continual improvement","D":"Service level management"},"answer":"B","category":"Continual Improvement"},{"id":262,"question":"Which is a way of applying the guiding principle ‘focus on value’?","options":{"A":"Understanding how service consumers use services","B":"Comprehending the whole, but doing something","C":"Recognizing the complexity of systems","D":"Doing fewer things, but doing them better"},"answer":"A","category":"Guiding Principles"},{"id":263,"question":"Which of the following is NOT recommended by the guiding principle ‘start where you are’?","options":{"A":"Asking questions that appear to be stupid","B":"Identifying what is available to be leveraged","C":"Building something completely new","D":"Collecting data directly from the source"},"answer":"C","category":"Guiding Principles"},{"id":264,"question":"Which is a use of a continual improvement register?","options":{"A":"Planning changes, assisting in communication, avoiding conflicts, and assigning resources","B":"Selecting the right method, model or technique for identifying improvements","C":"Tracking and managing improvement ideas from identification through to final action","D":"Describing the services designed to meet the needs of a consumer group"},"answer":"C","category":"Continual Improvement"},{"id":265,"question":"Which practice uses pre-defined, standardized procedures to enable fulfilment times to be clearly communicated?","options":{"A":"Incident management","B":"Service level management","C":"Problem management","D":"Service request management"},"answer":"D","category":"Incident Management"},{"id":266,"question":"Which TWO of the following are considerations of change enablement? 1. Managing the people aspects of change 2. Ensuring that organizational transformations are successful 3. Maximizing the number of successful service changes 4. Ensuring that changes are properly assessed","options":{"A":"1 and 2","B":"2 and 3","C":"3 and 4","D":"1 and 4"},"answer":"C","category":"Change Enablement"},{"id":267,"question":"How can a service consumer contribute to the reduction of risk?","options":{"A":"By providing the service in accordance with requirements","B":"By ensuring that the service provider's resources are correctly configured","C":"By fully understanding their own requirements for the service","D":"By managing the detailed level of risk on behalf of the service provider"},"answer":"C","category":"General Concepts"},{"id":268,"question":"In which case would a problem be logged as part of the problem identification?","options":{"A":"When the cause is identified but not resolved","B":"After receiving of error information from a supplier","C":"When a user reports an unplanned service interruption","D":"After a workaround is identified and documented"},"answer":"B","category":"Problem Management"},{"id":269,"question":"Identify the missing word in the following sentence. The purpose of the service configuration management practice is to ensure that accurate and reliable information about the configuration of [?], and the CIs that support them, is available when and where it is needed.","options":{"A":"organizations","B":"outcomes","C":"IT assets","D":"services"},"answer":"D","category":"Service Configuration Management"},{"id":270,"question":"Which practice helps to ensure that the services delivered to customers are aligned with their needs?","options":{"A":"Service level management","B":"Change enablement","C":"Problem management","D":"Service request management"},"answer":"D","category":"Change Enablement"},{"id":271,"question":"Which service request management decisions require that policies are established?","options":{"A":"Deciding how degradations of service are resolved","B":"Deciding how to handle service requests where the steps are unknown","C":"Deciding which service requests require approval","D":"Deciding when workarounds should be used"},"answer":"C","category":"Problem Management"},{"id":272,"question":"Which dimension of service management considers how activities are coordinated?","options":{"A":"Organizations and people","B":"Information and technology","C":"Partners and suppliers","D":"Value streams and processes"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":273,"question":"A user contacts the service desk to ask how they can create a report. Which practice is MOST LIKELY to contribute to resolving this issue?","options":{"A":"Incident management","B":"Service level management","C":"Service request management","D":"Change enablement"},"answer":"C","category":"Change Enablement"},{"id":274,"question":"Which practice has a purpose that includes the management of financially valuable components that can contribute to the delivery of an IT service?","options":{"A":"Service configuration management","B":"IT asset management","C":"Change enablement","D":"Deployment management"},"answer":"B","category":"Change Enablement"},{"id":275,"question":"Which practice MOST requires staff who demonstrate skills such as empathy and emotional intelligence?","options":{"A":"Service request management","B":"Continual improvement","C":"Problem management","D":"Service desk"},"answer":"D","category":"Continual Improvement"},{"id":276,"question":"What is the customer of a service responsible for?","options":{"A":"Defining the requirements for the service","B":"Provisioning the service","C":"Using the service","D":"Authorizing the budget for the service"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":277,"question":"When using the ‘continual improvement model’, which information should be produced by an organization in order to understand where the organization is now?","options":{"A":"Business objectives","B":"Improvement plans","C":"Assessment results","D":"Measurable targets"},"answer":"C","category":"Continual Improvement"},{"id":278,"question":"Which statement about value streams is CORRECT?","options":{"A":"Each value stream must include all six value chain activities","B":"Each value stream must include suppliers or partners","C":"Each value stream must be designed for a specific scenario","D":"Each value stream must include all 34 ITIL practices"},"answer":"C","category":"Service Value Chain"},{"id":279,"question":"Which guiding principle recommends using ideas from ITIL, Lean, DevOps, Kanban, and other sources to help drive improvements?","options":{"A":"Optimize and automate","B":"Think and work holistically","C":"Start where you are","D":"Focus on value"},"answer":"A","category":"Guiding Principles"},{"id":280,"question":"Which is an activity in the 'problem control' phase of problem management?","options":{"A":"Re-assessing a known error to manage the ongoing impact","B":"Implementing a technical fix to resolve an issue","C":"Documenting the steps in a workaround","D":"Reviewing incident records to identify trends"},"answer":"C","category":"Problem Management"},{"id":281,"question":"Which practice nurtures links with stakeholders at strategic and tactical levels?","options":{"A":"Supplier management","B":"Relationship management","C":"Service desk","D":"Service level management"},"answer":"B","category":"Service Desk"},{"id":282,"question":"Which practice has a purpose that includes managing authentication and non-repudiation?","options":{"A":"Information security management","B":"Change enablement","C":"Service configuration management","D":"IT asset management"},"answer":"A","category":"Change Enablement"},{"id":283,"question":"Which statement about service offerings is CORRECT?","options":{"A":"The same product can be used as a basis for more than one service offering","B":"Service offerings include the transfer of goods from the consumer to the provider","C":"Service offerings describe service actions performed by users","D":"Each service should be described to consumers as a single service offering"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":284,"question":"What is a problem that has been analyzed but has not been resolved?","options":{"A":"Workaround","B":"Incident","C":"Known error","D":"Event"},"answer":"C","category":"Problem Management"},{"id":285,"question":"What ensures that a service provider and a service consumer continually co-create value?","options":{"A":"Service consumption","B":"Service offerings","C":"Service relationship management","D":"Service level management"},"answer":"C","category":"Service Level Management"},{"id":286,"question":"When working on an improvement iteration, which concept helps to ensure that the iteration activities remain appropriate in changing circumstances?","options":{"A":"Minimum viable product","B":"Feedback loop","C":"Analysis paralysis","D":"Direct observation"},"answer":"B","category":"General Concepts"},{"id":287,"question":"What is the definition of ‘service management’?","options":{"A":"A result for a stakeholder enabled by one or more outputs","B":"A formal description of one or more services, designed to address the needs of a target consumer group","C":"Joint activities performed by a service provider and a service consumer to ensure continual value co-creation","D":"A set of specialized organizational capabilities for enabling value for customers in the form of services"},"answer":"D","category":"General Concepts"},{"id":288,"question":"Which is a description of service provision?","options":{"A":"A way to help create value by facilitating outcomes that service consumers need","B":"Activities that an organization performs to deliver services","C":"A formal description of one or more services, designed to address the needs of a service consumer","D":"Cooperation between two organizations to ensure that a service delivers value"},"answer":"A","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":289,"question":"How is a ‘continual improvement register’ used?","options":{"A":"To provide a structured approach to implementing improvements","B":"To authorize changes to implement improvement initiatives","C":"To organize past, present, and future improvement ideas","D":"To record requests for provision of a resource or service"},"answer":"C","category":"Continual Improvement"},{"id":290,"question":"Which is an input to the service value system?","options":{"A":"A need from consumers for new or changed services.","B":"The system of directing and controlling an organization","C":"A model to help meet stakeholders’ expectations","D":"Recommendations to help an organization in all aspects of its work"},"answer":"A","category":"Service Value System"},{"id":291,"question":"Which organization delivers outputs or outcomes of a service?","options":{"A":"A service consumer delivers outcomes of the service","B":"A service consumer delivers outputs of the service","C":"A service provider delivers outcomes of the service","D":"A service provider delivers outputs of the service"},"answer":"C","category":"General Concepts"},{"id":292,"question":"Which practice requires focus and effort to engage and listen to the requirements, issues, concerns, and daily needs of customers?","options":{"A":"Service request management","B":"Service desk","C":"Supplier management","D":"Service level management"},"answer":"B","category":"Service Desk"},{"id":293,"question":"Which is the cause, or potential cause, of one or more incidents?","options":{"A":"A problem","B":"A known error","C":"An event","D":"A change"},"answer":"A","category":"Problem Management"},{"id":294,"question":"Which value chain activity is concerned with the availability of service components?","options":{"A":"Obtain/build","B":"Design and transition","C":"Deliver and support","D":"Plan"},"answer":"A","category":"Service Value Chain"},{"id":295,"question":"Which is the FIRST action when optimizing a service?","options":{"A":"Assess the current state","B":"Understand the organizational context","C":"Agree the future state","D":"Implement the improvements"},"answer":"B","category":"General Concepts"},{"id":296,"question":"Which practice would be MOST involved in assessing the risk to services when a supplier modifies the contract they offer to the organization?","options":{"A":"Service request management","B":"Change enablement","C":"Incident management","D":"Service level management"},"answer":"B","category":"Change Enablement"},{"id":297,"question":"Which is a financially valuable component that can contribute to the delivery of a service?","options":{"A":"Sponsor","B":"Configuration item","C":"IT asset","D":"Service offering"},"answer":"C","category":"Service Configuration Management"},{"id":298,"question":"Which term is used to describe removing something that could have an effort on a service?","options":{"A":"A change","B":"An incident","C":"A problem","D":"An IT asset"},"answer":"A","category":"General Concepts"},{"id":299,"question":"Which TWO BEST describe the guiding principles? 1. Short-term 2. Standards 3. Recommendations 4. Long-term","options":{"A":"1 and 4","B":"2 and 3","C":"3 and 4","D":"1 and 2"},"answer":"B","category":"Guiding Principles"},{"id":300,"question":"Which BEST describes the focus of the ‘think and work holistically’ principle?","options":{"A":"Breaking down large initiatives into smaller pieces of work","B":"Integrating an organization’s activities to deliver value","C":"Eliminating unnecessary steps to deliver valuable outcomes","D":"Considering the existing organizational assets before building something new"},"answer":"B","category":"Guiding Principles"},{"id":301,"question":"Which is the FIRST thing to consider when focusing on value?","options":{"A":"Defining customer experience and user experience","B":"Understanding what is valuable to the service consumer","C":"Ensuring value is co-created by improvement initiatives","D":"Identifying the service consumer who will receive value"},"answer":"B","category":"General Concepts"},{"id":302,"question":"Identify the missing word in the following sentence. An organization which is undertaking an improvement initiative should [?] the existing methods and services when building for the future.","options":{"A":"Discard","B":"Improve","C":"Consider","D":"Re-use"},"answer":"B","category":"General Concepts"},{"id":303,"question":"What is the difference between the ‘incident management’ and ‘service desk’ practices?","options":{"A":"Incident management resolves issues, service desk investigates the underlying causes of issues","B":"Incident management restores service operation, service desk provides communication with users","C":"Incident management manages interruptions to services, service desk monitors achieved service quality","D":"Incident management resolves complex issues, service desk resolves simpler issues"},"answer":"B","category":"Incident Management"},{"id":304,"question":"Which step of the ‘continual management model’ defines measurable targets?","options":{"A":"Where do we want to be?","B":"What is the vision?","C":"How do we get there?","D":"Where are we now?"},"answer":"A","category":"General Concepts"},{"id":305,"question":"What is included in the purpose of the ‘release management’ practice?","options":{"A":"Authorizing changes to proceed","B":"Making new features available for use","C":"Moving new software to live environments","D":"Ensuring information about services is available"},"answer":"B","category":"Release Management"},{"id":306,"question":"Why should a service level agreement include bundles of metrics?","options":{"A":"To reduce the number of metrics that need to be measured and reported","B":"To help focus on business outcomes, rather than operational results","C":"To ensure that the service levels have been agreed with customers","D":"To ensure that all services are included in the service reports"},"answer":"B","category":"Service Level Management"},{"id":307,"question":"Which of the four dimensions contributes MOST to defining activities needed to deliver services?","options":{"A":"Partners and suppliers","B":"Organizations and people","C":"Value streams and processes","D":"Information and technology"},"answer":"C","category":"Four Dimensions of Service Management"},{"id":308,"question":"Which practice balances management of risk with maximizing throughput?","options":{"A":"Problem management","B":"Incident management","C":"Continual improvement","D":"Change enablement"},"answer":"D","category":"Continual Improvement"},{"id":309,"question":"Which is recommended as part of the ‘progress iteratively with feedback’ guiding principle?","options":{"A":"Analyze the whole situation in detail before taking any action","B":"Reduce the number of steps that produce tangible results","C":"Prohibit changes to plans after they have been finalized","D":"Organize work into small manageable units"},"answer":"D","category":"Guiding Principles"},{"id":310,"question":"What is included in the purpose of the ‘continual improvement’ practice?","options":{"A":"Creating collaborative relationships with key suppliers to realize new value","B":"Aligning the organization’s practices and services with changing business needs","C":"Identifying and continually improving relationships with and between stakeholders","D":"Ensuring that delivery of services is properly assessed, monitored, and improved against targets"},"answer":"B","category":"Continual Improvement"},{"id":311,"question":"How does the ‘incident management’ practice set user expectations?","options":{"A":"By using collaboration tools to communicate effectively","B":"By agreeing, and communicating target resolution times","C":"By assigning resources to ensure that all incidents are resolved as quickly as possible","D":"By automated matching of incidents to known errors"},"answer":"B","category":"Incident Management"},{"id":312,"question":"What is a user?","options":{"A":"The role that defines the requirements for a service","B":"The role that directs and controls an organization","C":"The role that uses services","D":"The role that authorizes budget for service consumption"},"answer":"C","category":"Key Concepts (Value, Outcomes, Costs, Risks)"},{"id":313,"question":"How do ‘continual improvement registers’ help to create value?","options":{"A":"By making improvements visible","B":"By monitoring achievement against service level targets","C":"By assigning change authorities for change requests","D":"By documenting all improvement ideas in a single place"},"answer":"A","category":"Continual Improvement"},{"id":314,"question":"Which statement about the inputs and outputs of the value chain activities is CORRECT?","options":{"A":"Each value chain activity receives inputs and provides outputs","B":"The organization’s governance will determine the inputs and outputs of each value chain activity","C":"Some value chain activities only have inputs, whereas others only have outputs","D":"Inputs and outputs are fixed for each value chain activity"},"answer":"A","category":"Service Value Chain"},{"id":315,"question":"What is the value of a service?","options":{"A":"A tangible or intangible deliverable of the service","B":"The amount of money that is created or saved for the service consumers by using the service","C":"The benefits, usefulness, or importance of the service, as perceived by the stakeholders","D":"A result for a stakeholder enabled by the outputs of the service"},"answer":"C","category":"General Concepts"},{"id":316,"question":"Which is the MOST LIKELY way of resolving major incidents?","options":{"A":"A support team following detailed procedures for investigating the incident","B":"Users establishing a resolution using self-help","C":"A temporary team working together to identify a resolution","D":"The service desk identifying the cause and a resolution"},"answer":"C","category":"Service Desk"},{"id":317,"question":"What is the CORRECT order for the three phases of problem management?","options":{"A":"Problem control, error control, problem identification","B":"Problem identification, problem control, error control","C":"Error control, problem control, problem identification","D":"Problem identification, error control, problem control"},"answer":"B","category":"Problem Management"},{"id":318,"question":"What is included in the purpose of the 'IT asset management’ practice?","options":{"A":"Supporting decision-making about purchase, re-use, retirement, and disposal of assets","B":"Providing information on how assets are configured and the relationships between them","C":"Making new and changed assets available for use","D":"Moving assets to live or other environments for testing or staging"},"answer":"A","category":"IT Asset Management"},{"id":319,"question":"Which component is focused on the activities needed by an organization to help it co-create value?","options":{"A":"Guiding principles","B":"Service value chain","C":"Continual improvement","D":"Practices"},"answer":"B","category":"Guiding Principles"},{"id":320,"question":"Why and how is a user MOST LIKELY to contact the service desk?","options":{"A":"To discuss the cause of an incident via a phone call","B":"To report a problem using a mobile app","C":"To request access to a resource via a self-service portal","D":"To authorize an emergency change via live chat"},"answer":"C","category":"Change Enablement"},{"id":321,"question":"What is used as a tool to help define and measure performance?","options":{"A":"A change schedule","B":"An incident record","C":"A continual improvement register","D":"A service level agreement"},"answer":"D","category":"Continual Improvement"},{"id":322,"question":"Which of the four dimensions contributes is concerned with service integration and management?","options":{"A":"Partners and suppliers","B":"Organizations and people","C":"Value streams and processes","D":"Information and technology"},"answer":"D","category":"Four Dimensions of Service Management"},{"id":323,"question":"What may form part of a service request procedure?","options":{"A":"The timescale for restoration of service","B":"The method of diagnosing the cause","C":"Authorization in accordance with a security policy","D":"Escalation to the appropriate change authority"},"answer":"C","category":"Change Enablement"},{"id":324,"question":"When applying the ‘collaborate and promote visibility’ principle to an organization’s initiative, which is NOT a necessary action?","options":{"A":"Basing decisions about the initiative on visible data","B":"Communicating information about the initiative to other parts of the organization","C":"Ensuring everyone involved in the initiative is in agreement about it before starting","D":"Considering different methods of communication for the different audiences"},"answer":"C","category":"Guiding Principles"},{"id":325,"question":"Which practice identifies changes of state related to infrastructure, services, and business processes?","options":{"A":"Monitoring and event management","B":"Service configuration management","C":"Change enablement","D":"Information security management"},"answer":"A","category":"Change Enablement"},{"id":326,"question":"Identity the missing word(s) in the following sentence. When an organization is assessing its current state, it should use [?] to obtain accurate measurements.","options":{"A":"Reports","B":"Assumptions","C":"Source data","D":"Risk management techniques"},"answer":"C","category":"General Concepts"},{"id":327,"question":"How should a process design allow for exceptional situations?","options":{"A":"Create rules to handle exceptions generally","B":"Remove the option for process exceptions","C":"Create an additional process for each exception","D":"Include all exception steps in the main process"},"answer":"A","category":"General Concepts"},{"id":328,"question":"Which practice needs the right culture to be embedded across the entire organization?","options":{"A":"Service request management","B":"Service level management","C":"Change enablement","D":"Continual improvement"},"answer":"D","category":"Continual Improvement"},{"id":329,"question":"Which term could be used to refer to a single person who has independently subscribed to a service?","options":{"A":"Supplier","B":"Service desk","C":"Service provider","D":"Organization"},"answer":"D","category":"Service Desk"},{"id":330,"question":"What is the MOST LIKELY reason that incident management would need a temporary team to work together?","options":{"A":"To escalate an incident to a supplier or partner","B":"So customers and users are provided with timely updates","C":"To resolve a complex or major incident","D":"So users can resolve their own incidents with self-help"},"answer":"C","category":"Incident Management"},{"id":331,"question":"Which is MOST LIKELY to be achieved by following a detailed procedure?","options":{"A":"Assessing a change","B":"Resolving an incident","C":"Managing a service request","D":"Investigating a problem"},"answer":"C","category":"Service Request Management"},{"id":332,"question":"Which of the four dimensions focuses on roles, responsibilities, and systems of authority?","options":{"A":"Value streams and processes","B":"Partners and suppliers","C":"Organizations and people","D":"Information and technology"},"answer":"C","category":"Four Dimensions of Service Management"},{"id":333,"question":"What is CORRECT about service request management?","options":{"A":"Service requests can be used to restore service","B":"Complex service request procedures should be avoided","C":"Compliments can be handled as service requests","D":"A new procedure is required for each new service request"},"answer":"C","category":"Service Request Management"}];
